\r\n        openCreateService() {\r\n            this.showFormCreateService = true;\r\n        },\r\n        add(data) {\r\n            this.items = [...this.items, data];\r\n            this.form.item_id = data.id;\r\n            this.changeItem();\r\n        },\r\n        async getTables() {\r\n            try {\r\n                this.loading = true;\r\n                const response = await this.$http.get(\r\n                    `${this.resource}/tables`\r\n                );\r\n                const { items } = response.data;\r\n                this.items = items;\r\n            } catch (e) {\r\n                console.log(e);\r\n                this.$toast.error(\"Ocurrió un problema\");\r\n            } finally {\r\n                this.loading = false;\r\n            }\r\n        },\r\n        initItemForm() {\r\n            this.form.item_id = null;\r\n            this.form.disabled = false;\r\n            this.price = null;\r\n        },\r\n        deleteService(id) {\r\n            this.services = this.services.filter(s => s.item_id != id);\r\n        },\r\n        addItem() {\r\n            let item = this.items.find(i => i.id == this.form.item_id);\r\n            // let { id } = item;\r\n\r\n            this.services = [item];\r\n            // this.initItemForm();\r\n        },\r\n        changeItem() {\r\n            this.addItem();\r\n        },\r\n        async searchRemoteItems(input) {\r\n            if (input.length > 2) {\r\n                if (this.timer) {\r\n                    clearTimeout(this.timer);\r\n                }\r\n                this.timer = setTimeout(async () => {\r\n                    try {\r\n                        let parameters = `input=${input}`;\r\n                        this.loading_search = true;\r\n                        const response = await this.$http.get(\r\n                            `/documents/data-table/items?service=1&${parameters}`\r\n                        );\r\n\r\n                        this.items 